int tsp(const vector<vector<int>>& cost) {
    int n = cost.size();
    vector<int> cities(n);
    for (int i = 0; i < n; ++i) {
        cities[i] = i;
    }

    int minCost = INT_MAX;
    do {
        int costOfCurrentPath = calculateCost(cost, cities);
        minCost = min(minCost, costOfCurrentPath);
    } while (next_permutation(cities.begin() + 1, cities.end()));  // Keep start city fixed

