#include <stdio.h>
#include <limits.h>
#include <string.h>

// Function to calculate the total cost of a given path
int calculateCost(int cost[][10], int path[], int n) {
    int totalCost = 0;
    for (int i = 0; i < n - 1; ++i) {
        totalCost += cost[path[i]][path[i + 1]];
    }
    totalCost += cost[path[n - 1]][path[0]];  // Return to starting city
    return totalCost;
}

// Function to generate all permutations of cities and calculate the minimum cost
int tsp(int cost[][10], int n) {
    int cities[10];
    for (int i = 0; i < n; ++i) {
        cities[i] = i;
    }

    int minCost = INT_MAX;

    // Generate all permutations of cities (except the first city, which is fixed)
    int factorial = 1;
    for (int i = 1; i <= n - 1; ++i) {
        factorial *= i;
    }

    do {
        int costOfCurrentPath = calculateCost(cost, cities, n);
        if (costOfCurrentPath < minCost) {
            minCost = costOfCurrentPath;
        }

        // Generate next permutation
        int i = n - 2;
        while (i >= 0 && cities[i] > cities[i + 1]) {
            --i;
        }
        if (i >= 0) {
            int j = n - 1;
            while (cities[i] > cities[j]) {
                --j;
            }
            int temp = cities[i];
            cities[i] = cities[j];
            cities[j] = temp;

            int k = i + 1;
            j = n - 1;
            while (k < j) {
                temp = cities[k];
                cities[k] = cities[j];
                cities[j] = temp;
                ++k;
                --j;
            }
        }
    } while (factorial--);

    return minCost;
}

int main() {
    int n;
    scanf("%d", &n);

    // Initialize the cost matrix
    int cost[10][10];

    // Take input for the cost matrix
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            scanf("%d", &cost[i][j]);
        }
    }

    // Calling the TSP function and getting the result
    int result = tsp(cost, n);

    // Output the minimum cost
    printf("%d\n", result);

    return 0;
}

