import java.util.*;

 class TSP {

    // Function to calculate the total cost of a given path
    public static int calculateCost(int[][] cost, int[] path) {
        int totalCost = 0;
        for (int i = 0; i < path.length - 1; ++i) {
            totalCost += cost[path[i]][path[i + 1]];
        }
        totalCost += cost[path[path.length - 1]][path[0]];  // Return to starting city
        return totalCost;
    }

    // Function to generate all permutations of cities and calculate the minimum cost
    public static int tsp(int[][] cost) {
        int n = cost.length;
        Integer[] cities = new Integer[n];
        for (int i = 0; i < n; i++) {
            cities[i] = i;
        }

        int minCost = Integer.MAX_VALUE;

        // Generate all permutations of cities (except the first city, which is fixed)
        List<List<Integer>> permutations = permute(cities, 1, n);

        // Check each permutation
        for (List<Integer> perm : permutations) {
            int[] path = new int[n];
            path[0] = 0;  // Fix the starting city at index 0
            for (int i = 1; i < n; ++i) {
                path[i] = perm.get(i - 1);
            }
            int costOfCurrentPath = calculateCost(cost, path);
            minCost = Math.min(minCost, costOfCurrentPath);
        }

        return minCost;
    }

    // Function to generate permutations of cities (except the first city)
    public static List<List<Integer>> permute(Integer[] arr, int start, int end) {
        List<List<Integer>> result = new ArrayList<>();
        if (start == end) {
            List<Integer> temp = new ArrayList<>();
            for (int i = 1; i < arr.length; i++) {
                temp.add(arr[i]);
            }
            result.add(temp);
        } else {
            for (int i = start; i < end; i++) {
                swap(arr, start, i);
                result.addAll(permute(arr, start + 1, end));
                swap(arr, start, i); // backtrack
            }
        }
        return result;
    }

    // Utility function to swap two elements in the array
    public static void swap(Integer[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        // Take input for the number of cities
        int n = sc.nextInt();

        // Initialize the cost matrix
        int[][] cost = new int[n][n];

        // Take input for the cost matrix
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                cost[i][j] = sc.nextInt();
            }
        }

        // Calling the TSP function and getting the result
        int result = tsp(cost);

        // Output the minimum cost
        System.out.println(result);
    }
}
